// Script: generar_42_editar_eliminar_medicamento_enfermedad_obs.js
// Que hace: replica el patron de Editar/Eliminar (ya con el z-index
// correcto desde el inicio) a Medicamentos, Enfermedades, y
// Observaciones. Con esto, las 5 secciones principales de Prevencion
// (Vacunas, Antiparasitarios, Medicamentos, Enfermedades, Observaciones)
// ya tienen edicion y eliminacion completas.
//
// Detalles especiales:
//   - Medicamentos: el campo "Indicado por veterinario" se precarga
//     correctamente al editar.
//   - Enfermedades y Observaciones: si al editar se elige una foto
//     nueva, reemplaza la anterior (se sube con el mismo id, asi que
//     ocupa la misma ruta de Storage). Si no se toca la foto, se
//     mantiene la que ya tenia.
//
// Examenes queda pendiente para una entrega aparte (ya tiene boton de
// eliminar desde antes, pero editar es mas delicado por el archivo PDF
// adjunto, asi que se evaluara por separado).
//
// Como correrlo: node generar_42_editar_eliminar_medicamento_enfermedad_obs.js
// Confirma "OK: app/prevencion/page.tsx"

const fs = require('fs');
const path = require('path');

const filePath = path.join('app', 'prevencion', 'page.tsx');
const b64 = "";
const content = Buffer.from(b64, 'base64').toString('utf8');

const dir = path.dirname(filePath);
if (!fs.existsSync(dir)) fs.mkdirSync(dir, { recursive: true });

fs.writeFileSync(filePath, content, 'utf8');
console.log('OK: ' + filePath);
